import{_ as t,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as s,o as d,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Добавление канала GitHub Releases","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/github-releases.md","filePath":"ru-RU/upload/github-releases.md","lastUpdated":1781962217000}'),r={name:"ru-RU/upload/github-releases.md"};function l(n,e,c,p,h,b){return d(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="добавление-канала-github-releases" tabindex="-1">Добавление канала GitHub Releases <a class="header-anchor" href="#добавление-канала-github-releases" aria-label="Permalink to &quot;Добавление канала GitHub Releases&quot;">​</a></h1><h2 id="что-подготовить-заранее" tabindex="-1">Что подготовить заранее <a class="header-anchor" href="#что-подготовить-заранее" aria-label="Permalink to &quot;Что подготовить заранее&quot;">​</a></h2><p>Нужны всего три вещи:</p><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт GitHub</td><td>Для создания access token и владения репозиторием.</td></tr><tr><td>GitHub Access Token</td><td>ImgBed использует его для доступа к GitHub API, создания releases и загрузки файлов.</td></tr><tr><td>Имя репозитория</td><td>Можно ввести только имя репозитория, например <code>image</code>.</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="шаг-1-воидите-в-github-и-создаите-access-token" tabindex="-1">Шаг 1. Войдите в GitHub и создайте Access Token <a class="header-anchor" href="#шаг-1-воидите-в-github-и-создаите-access-token" aria-label="Permalink to &quot;Шаг 1. Войдите в GitHub и создайте Access Token&quot;">​</a></h3><ol><li>Войдите в GitHub.</li><li>Нажмите аватар в правом верхнем углу и откройте <code>Settings</code>.</li><li>В левой боковой панели откройте <code>Developer settings</code>.</li><li>Откройте <code>Personal access tokens</code>.</li><li>Откройте <code>Tokens (classic)</code>.</li><li>Нажмите <code>Generate new token (classic)</code>.</li><li>Дайте token понятное имя.</li><li>Выберите срок действия по своему подходу к обслуживанию.</li><li>Выберите scopes <code>repo</code> и <code>workflow</code>.</li><li>Сразу после создания скопируйте и сохраните token.</li></ol><p><img src="'+t+'" alt="Добавление прав GitHub" loading="lazy"></p><h2 id="шаг-2-заполните-канал-github-releases-в-imgbed" tabindex="-1">Шаг 2. Заполните канал GitHub Releases в ImgBed <a class="header-anchor" href="#шаг-2-заполните-канал-github-releases-в-imgbed" aria-label="Permalink to &quot;Шаг 2. Заполните канал GitHub Releases в ImgBed&quot;">​</a></h2><p>После выбора <code>GitHub Releases</code> в настройках загрузки заполните поля:</p><table tabindex="0"><thead><tr><th>Поле в интерфейсе</th><th>Что ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Имя на ваш выбор, например <code>GitHubPrimary</code>.</td></tr><tr><td>Access Token</td><td>GitHub Personal Access Token, который вы только что создали.</td></tr><tr><td>Repository name</td><td>Короткое имя repo, например <code>image</code>, или полный путь вроде <code>username/image</code>.</td></tr><tr><td>Private repository</td><td>Включите или выключите по своим потребностям.</td></tr><tr><td>Remark</td><td>Необязательно, например <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="Заполнение конфигурации GitHub-канала" loading="lazy"></p><h2 id="шаг-3-сохраните-канал" tabindex="-1">Шаг 3. Сохраните канал <a class="header-anchor" href="#шаг-3-сохраните-канал" aria-label="Permalink to &quot;Шаг 3. Сохраните канал&quot;">​</a></h2><p>После заполнения полей нажмите Save.</p><p>Система сама обработает:</p><table tabindex="0"><thead><tr><th>Поведение системы</th><th>Описание</th></tr></thead><tbody><tr><td>Короткое имя репозитория</td><td>ImgBed определяет текущий аккаунт GitHub и разворачивает значение в полный путь репозитория.</td></tr><tr><td>Полный путь репозитория</td><td>ImgBed использует путь <code>username/repository</code> ровно в том виде, как он введен.</td></tr><tr><td>Проверка репозитория</td><td>Если используется путь текущего личного аккаунта, ImgBed автоматически создает репозиторий, если его еще нет. Если полный путь введен вручную, ImgBed использует его напрямую.</td></tr><tr><td>Публичный или приватный статус</td><td>Видимость репозитория синхронизируется с текущим переключателем.</td></tr></tbody></table><h2 id="короткии-чек-лист" tabindex="-1">Короткий чек-лист <a class="header-anchor" href="#короткии-чек-лист" aria-label="Permalink to &quot;Короткий чек-лист&quot;">​</a></h2><p>GitHub Releases работает так:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Войти в GitHub</span></span>
<span class="line"><span>-&gt; Создать Access Token</span></span>
<span class="line"><span>-&gt; Вернуться в ImgBed и ввести token и имя репозитория</span></span>
<span class="line"><span>-&gt; Сохранить</span></span>
<span class="line"><span>-&gt; Если введено только имя repo, ImgBed автоматически добавит текущий username</span></span>
<span class="line"><span>-&gt; Если введено username/repo, ImgBed использует это как есть</span></span>
<span class="line"><span>-&gt; Загрузить тестовое изображение</span></span></code></pre></div>`,19)])])}const k=s(r,[["render",l]]);export{g as __pageData,k as default};
